var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배! 어디에 있어?","JPN":"先輩！　どこにいるの？","ENG":"Shiyoon! Where are you?","TWN":"前輩！你在哪裡？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이쪽입니다.","JPN":"こっちですよ。","ENG":"Here.","TWN":"我在這裡。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이 안개와 바람은 대체 뭐야? 앞이 하나도 안 보여!","JPN":"この霧と風はいったい何なの？　前が全然見えないよ！","ENG":"What’s up with all the wind and fog? I can’t see a thing!","TWN":"這裡的霧跟風會不會太誇張？根本看不到前面啊！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이 지역에 존재하는 차원 폭풍 때문인 것 같네요.","JPN":"この地域に発生している次元の暴風のようですね。","ENG":"I think it’s because of the dimensional storm.","TWN":"應該是因為這個地區的次元風暴。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"관리국 기상정보에 따르면 지금이 그나마 이쪽 루트의 차원 폭풍이 약해지는 시간대입니다.","JPN":"管理局の気象情報によると、\\nちょうど今がこのあたりの次元の暴風が弱まる時間帯です。","ENG":"According to the Administration’s forecast, now is the time when the storm on this route gets calmer.","TWN":"根據管理局的氣象報告，現在應該是這一條路線的次元風暴減弱的時段。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"시간이 조금만 지나면 차원 함선도 제대로 움직이기 어려울 겁니다.","JPN":"このタイミングを逃すと次元艦船も動かせなくなるでしょう。","ENG":"Soon it will get really serious; even the Dimensional Ship won’t be able to move.","TWN":"再過些時間，很可能連次元艦船都很難移動。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 정도야?","JPN":"そんなに？","ENG":"It’s that bad?","TWN":"這麼誇張？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"물건만 가지고 오면 되는 줄 알았는데……. 역시 쉬운 게 없네.","JPN":"物を取ってくるだけで終わると思ってたのに……やっぱり簡単にはいかないね。","ENG":"I thought this was just a simple retrieval mission... But I guess there are no easy jobs.","TWN":"我還以為只要帶傢伙來就好……果然沒有那麼簡單的事。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하. 남의 돈 받아내기가 쉬울 리 있나요.","JPN":"ハハ。お金を稼ぐのは大変ですから。","ENG":"Haha. That’s why people pay us the big bucks.","TWN":"哈哈，要賺別的人錢哪有這麼容易的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"할 수 없지, 뭐.","JPN":"しょうがないね。","ENG":"Yeah, you’re right.","TWN":"也只能這樣囉～"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"상황이 더 나빠지기 전에 빨리 가서 일 끝내고 쉬자고…… ","JPN":"状況がもっと悪くなる前に早く片付けて……","ENG":"Let's finish this before it gets worse...","TWN":"在情況更惡劣之前，趕緊把事情辦完回家休息吧…… "},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":" 응?","JPN":"ん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"여봐라, 혹시 거기 듣고 있는 필멸자 녀석 있느냐?","JPN":"だれかこの声を聞いている定命の者はおらぬか？","ENG":"Hail, are there any mortals who can hear me?","TWN":"喂，那裡有必滅者在聽嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"이게 그러니까…… 뭐라고 하더라, 시종?","JPN":"これは……僕よ、なんといったものだったか？","ENG":"This is... um, what do you call it, my servant?","TWN":"這是那個……那個什麼？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"조난 신호입니다, 주인님.","JPN":"遭難信号でございます、ご主人様。","ENG":"It’s a distress call, Mistress.","TWN":"主人，是求救訊號。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"그래! 조난 신호다!","JPN":"そうじゃ！　遭難信号じゃ！","ENG":"Yes, this is a distress call!","TWN":"沒錯！就是求救訊號！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"이 고귀한 몸께서 위험에 처한 것이지.","JPN":"この高貴な身が危険にさらされているのじゃ。","ENG":"I, the noblest being of them all, am endangered.","TWN":"意思就是我這高貴的身軀現在有危險。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"그러니 이 연락을 받은 필멸자들은 즉시 하던 일을 모두 멈추고 이 몸을 구하러 오너라.","JPN":"この連絡を受けた定命の者は直ちにすべての任務を中断し、\\n妾を助けに来るがよい。","ENG":"So any mortals who hear this call must come here at once and save me!","TWN":"聽到這段求救訊號的必滅者，立刻放下手邊的工作來救我！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NULL_QM","text":{"KOREA":"이상이다! 아하하핫!","JPN":"以上じゃ！　アーッハッハッハッハ！","ENG":"Over! Ahaha!","TWN":"以上！哇哈哈哈哈！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 방금?","JPN":"い、今のは……何？","ENG":"What? What was that?","TWN":"剛剛…那是怎樣？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"내용이 조금 이상하지만…… 조난 신호는 맞을 것 같네요.","JPN":"内容は少し変ですが……遭難信号であることは間違いないようです。","ENG":"That sounded very weird... but I think it was a distress call.","TWN":"雖然內容有點奇怪……但似乎確實是求救訊號沒錯。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"지금 시간대에는 이 루트를 제외하면 차원 폭풍이 매우 심하니 말입니다.","JPN":"この時間帯の別ルートは次元の暴風が激しく吹き荒れていますから。","ENG":"At this time of day, dimensional storms can be very heavy outside of this route.","TWN":"現在這個時段，其他地方的次元風暴應該都非常強烈。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"작전 중이던 용병들이 조난당했다고 해도 이상한 일은 아니죠.","JPN":"作戦中だった傭兵たちが遭難してもおかしくありません。","ENG":"So it’s possible that some mercenaries are lost in the storm.","TWN":"就算有傭兵在作戰中遇難也也不足為奇吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 위험하다는 뜻이잖아. 구하러 가야 하는 거 아냐, 선배?","JPN":"ってことは危険な状態なんだね。先輩、助けに行った方がいいんじゃない？","ENG":"It means they could be in danger, right? Maybe we should go save them.","TWN":"就是有危險的意思嘛！前輩，那我們應該要去救人吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 함부로 움직였다간 저희들까지 조난될 수 있습니다.","JPN":"ですが、むやみに動けば僕たちまで遭難するかもしれません。","ENG":"But it could be dangerous for us as well.","TWN":"太輕舉妄動，搞不好連我們都會遇難。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"더구나 우리에겐 의뢰인이 맡긴 임무도 있고요.","JPN":"それに僕たちには依頼された任務もあります。","ENG":"We also have a mission from our client.","TWN":"更何況我們還身負委託人交付的任務。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"시간이 지체되면 차원 폭풍이 강해져서 이 루트로도 등대에 접근하지 못하게 될 겁니다.","JPN":"遅れてしまうと次元の暴風が強くなって、このルートからも灯台に近づけなくなりますよ。","ENG":"If we tarry here, the dimensional storm will get worse, and we won’t be able to approach the Lighthouse via any route.","TWN":"萬一耽誤到時間，我擔心次元風暴會變強，到時候可能連這條路線也無法靠近燈塔。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래도 사람이 위험한 걸 뻔히 아는데 그냥 둘 수는 없잖아.","JPN":"でも、誰かが危険な状態ってことを知っていながら、\\n放っておくわけにはいかないよ。","ENG":"But if there are people in danger, we can’t just leave them behind.","TWN":"問題是現在明明就知道有人有危險，怎麼可能坐視不管！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"우리가 조난됐을 때 아무도 안 도와 주면 어떻겠어.","JPN":"私たちが遭難したとして、誰も助けに来てくれなかったらどう思う？","ENG":"How would you feel if no one helps us when we’re in such a situation?","TWN":"如果今天遇難的是我們，結果都沒有人來幫我們，那你會怎麼樣？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"흐음……. 그건 조금 섭섭하겠네요.","JPN":"ふむ……それは少し寂しいですね。","ENG":"Hmm... I guess I’d be disappointed.","TWN":"嗯……應該會有點難過吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러면 작전은 여기서 포기인가요?","JPN":"それでは作戦はここで諦めますか？","ENG":"So, are we aborting the mission?","TWN":"那現在意思是要放棄任務嗎？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그건 절대 안 돼!","JPN":"そ、それだけは絶対にダメ！","ENG":"W-we can’t do that!","TWN":"什…當然不行囉！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런 짓을 했다간 부사장님께 무슨 소릴 들을지 상상만 해도 무서워…….","JPN":"そんなことをしたら副社長になんて言われるか、想像しただけでゾッとするよ……","ENG":"I can’t even imagine what the Vice President will say...","TWN":"要是放棄的話，回去後副總不知道又要說什麼，光想就令我害怕……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 억지로 부탁한 거니까, 나 혼자만 조난자들을 구하러 갈게.","JPN":"私が無理を言っているのはわかってるから、私だけで遭難者たちを助けに行くよ。","ENG":"Well, I’m the one who wanted to help them, so I’ll go save them by myself.","TWN":"是我堅持要去救人的，所以我自己去就好。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배는 이대로 작전을 진행해 줘.","JPN":"先輩はこのまま作戦を進行して。","ENG":"Shiyoon, you go ahead with the mission.","TWN":"前輩你就繼續執行任務吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"조난자에게 탈출로를 안내해 주는 정도라면 나 혼자서라도 가능할 거야.","JPN":"遭難者に脱出路を案内するくらいなら、私一人でもできるよ。","ENG":"Guiding them out of the storm won’t be too hard. I can do it alone.","TWN":"我只是去告訴他們逃生的路線，自己一個人應該沒問題。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"호오……?","JPN":"ほう……？","ENG":"Oh?","TWN":"這樣喔……？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 샬롯, 그렇게 말해 놓고 미안하지만 넌 선배를 따라서…….","JPN":"シャーロット、頼っていいって言ったのにごめんね。あなたは先輩と一緒に……","ENG":"Carlota, I know I told you I was going to help you, but you’ll have to go with Shiyoon...","TWN":"那個，夏洛特不好意思，我自己擅作主張，你就跟前輩一起……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"아니. 나도 너와 함께 조난자를 도우러 가겠다.","JPN":"いや、私も君と一緒に遭難者を助けに行く。","ENG":"No. I’m coming with you.","TWN":"不，我也要和你一起去救人。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐?","JPN":"えっ？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"늑대…… 아니, 나의 친구도 너와 같은 선택을 했을 테니까.","JPN":"狼……いや、私の友達もきっと君と同じ選択をしたはず。","ENG":"The Wolf... I mean, my friend would have made the same call.","TWN":"因為那隻狼……不，我的朋友應該也會跟你做出同樣的選擇。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHARLOTTE_ORDER_NULL_NULL","text":{"KOREA":"볼수록 넌 그녀와 닮은 것 같다. 나도 돕고 싶다.","JPN":"見れば見るほど君は彼女に似ている。だから力になりたい。","ENG":"The more I get to know you, the more you remind me of her. I want to help.","TWN":"我越來越覺得你們很像，我也想幫忙。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그래?","JPN":"そ、そう？","ENG":"Y-you do?","TWN":"是喔？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만 그러면 선배 혼자 움직여야 할 텐데…….","JPN":"でも、そうなると先輩が一人で行動しなきゃいけなくなるけど……","ENG":"But that means Shiyoon will have to go alone...","TWN":"那這樣前輩會落單欸……"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"전 신경 쓰지 마세요, 미나 양. 미움 받는 삶은 익숙하거든요.","JPN":"ミナさん、僕のことは気にしなくていいですよ。嫌われることには慣れていますから。","ENG":"Don’t worry about me, Mina. I’m used to being shunned.","TWN":"米娜，你不用擔心我，我很習慣被討厭的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그, 그런 뜻이 아니라……!","JPN":"そ、そういう意味じゃ……！","ENG":"I-I didn’t mean that!","TWN":"我沒那個意思啦……！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하하, 농담입니다.","JPN":"ハハ、冗談ですよ。","ENG":"Haha. I was just kidding.","TWN":"哈哈，我開玩笑的啦。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"등대 일은 제게 맡기세요, 미나 양. 사람들을 구하는 일이잖아요?","JPN":"灯台のことは任せてください。ミナさん、人助けも大事ですからね。","ENG":"Let me take care of the Lighthouse, Mina. Your job is to save people, right?","TWN":"燈塔的事就交給我，你們去救人吧！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"놀랐잖아, 진짜!","JPN":"ビックリしたじゃん、もう！","ENG":"You got me there for a second!","TWN":"討厭，幹嘛嚇我！"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼 잘 부탁해, 선배. 우리도 조난자를 구하고 나서 최대한 빨리 합류할게.","JPN":"じゃあよろしくね、先輩。私たちも遭難者を助けたらすぐに合流するから。","ENG":"Okay, then. We’ll catch up with you as soon as possible after we save the castaways.","TWN":"前輩，那就拜託你囉！等我們把那些遇難者安頓好後，就盡快去找你。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLOTTE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};